Param(     [string]$ProjectRoot = "C:\杞欢\trader",     [string]$ApiUrl = "http://127.0.0.1:18080/health",     [string]$MySqlHost = "127.0.0.1",     [int]$MySqlPort = 3306,     [string]$MySqlIniPath = "",     [string]$ExpectedServerPublicIp = "",     [string]$ExpectedStrategyIp = "",     [switch]$DeepConfigCheck,     [switch]$CheckSystemTuning )  $ErrorActionPreference = "Continue"  $Script:PassCount = 0 $Script:WarnCount = 0 $Script:FailCount = 0  function Pass($msg) {     $Script:PassCount++     Write-Host "[PASS] $msg" -ForegroundColor Green }  function Warn($msg) {     $Script:WarnCount++     Write-Host "[WARN] $msg" -ForegroundColor Yellow }  function Fail($msg) {     $Script:FailCount++     Write-Host "[FAIL] $msg" -ForegroundColor Red }  function Section($title) {     Write-Host "`n=== $title ===" -ForegroundColor Cyan }  Section "0) 鍩虹璺緞涓庢枃浠? if (Test-Path -LiteralPath $ProjectRoot) {     Pass "椤圭洰鐩綍瀛樺湪: $ProjectRoot" } else {     Fail "椤圭洰鐩綍涓嶅瓨鍦? $ProjectRoot" }  $criticalFiles = @(     "src\config.py",     "src\adapters\ptrade_adapter.py",     "scripts\api_server.py",     "scripts\run_ems.py",     "scripts\ptrade_bridge_template.py",     "scripts\windows\go_live.ps1",     "scripts\windows\deploy_one_click.ps1",     "sql\create_trade_signals.sql" )  foreach ($f in $criticalFiles) {     $full = Join-Path $ProjectRoot $f     if (Test-Path -LiteralPath $full) { Pass "鏂囦欢瀛樺湪: $f" } else { Fail "缂哄皯鏂囦欢: $f" } }  Section "1) 鏈嶅姟鐘舵€? $services = @("EMS_API", "EMS_MAIL_INGEST") foreach ($svcName in $services) {     $svc = Get-Service -Name $svcName -ErrorAction SilentlyContinue     if ($null -eq $svc) {         Warn "鏈嶅姟鏈畨瑁? $svcName"     } elseif ($svc.Status -eq "Running") {         Pass "鏈嶅姟杩愯涓? $svcName"     } else {         Warn "鏈嶅姟鐘舵€侀潪 Running: $svcName => $($svc.Status)"     } }  $runnerSvc = Get-Service -Name "EMS_RUNNER" -ErrorAction SilentlyContinue if ($null -ne $runnerSvc) {     Warn "妫€娴嬪埌 EMS_RUNNER 鏈嶅姟瀛樺湪锛圥trade 鍦烘櫙涓嶆帹鑽愶級" } else {     Pass "鏈娴嬪埌 EMS_RUNNER 鏈嶅姟锛堢鍚?Ptrade 鍐呮ˉ鎺ヨ繍琛屾ā寮忥級" }  Section "2) API 涓庣綉缁滆繛閫? try {     $resp = Invoke-WebRequest -Uri $ApiUrl -UseBasicParsing -TimeoutSec 5     if ($resp.StatusCode -eq 200) {         Pass "API 鍋ュ悍妫€鏌ラ€氳繃: $ApiUrl"     } else {         Fail "API 杩斿洖闈?200: $($resp.StatusCode)"     } } catch {     Fail "API 鏃犳硶璁块棶: $ApiUrl" }  try {     $tnc = Test-NetConnection -ComputerName $MySqlHost -Port $MySqlPort -WarningAction SilentlyContinue     if ($tnc.TcpTestSucceeded) {         Pass "MySQL 绔彛杩為€? ${MySqlHost}:${MySqlPort}"     } else {         Fail "MySQL 绔彛涓嶉€? ${MySqlHost}:${MySqlPort}"     } } catch {     Warn "鏃犳硶鎵ц Test-NetConnection锛岃烦杩?MySQL 绔彛妫€娴? }  if ($ExpectedServerPublicIp) {     try {         $actualIp = (Invoke-WebRequest -Uri "https://ifconfig.me/ip" -UseBasicParsing -TimeoutSec 6).Content.Trim()         if ($actualIp -eq $ExpectedServerPublicIp) {             Pass "鍏綉 IP 绗﹀悎棰勬湡: $actualIp"         } else {             Warn "鍏綉 IP 涓庨鏈熶笉涓€鑷达紝瀹為檯=$actualIp锛岄鏈?$ExpectedServerPublicIp"         }     }     catch {         Warn "鏃犳硶鑾峰彇鍏綉 IP锛堝彲蹇界暐锛?     } }  Section "3) 閰嶇疆瀹夊叏妫€鏌? $configPath = Join-Path $ProjectRoot "src\config.py" if (Test-Path -LiteralPath $configPath) {     $cfg = Get-Content -LiteralPath $configPath -Raw      if ($cfg -match "change_me_to_a_strong_token") { Fail "API token 浠嶆槸榛樿鍗犱綅鍊? } else { Pass "API token 鐪嬭捣鏉ュ凡淇敼" }     if ($cfg -match "change_me_to_a_very_strong_secret") { Fail "HMAC secret 浠嶆槸榛樿鍗犱綅鍊? } else { Pass "HMAC secret 鐪嬭捣鏉ュ凡淇敼" }     if ($cfg -match "your_user" -or $cfg -match "your_password" -or $cfg -match "your_db") {         Fail "DB_CONFIG 浠嶅惈鍗犱綅绗?     } else {         Pass "DB_CONFIG 鐪嬭捣鏉ュ凡濉啓"     }      if ($cfg -match '"hmac_enabled"\s*:\s*True') {         Pass "宸插惎鐢?HMAC 閴存潈"     } else {         Warn "鏈娴嬪埌 hmac_enabled=True"     }      if ($ExpectedStrategyIp) {         if ($cfg -match [Regex]::Escape($ExpectedStrategyIp)) {             Pass "閰嶇疆涓娴嬪埌绛栫暐鏈?IP 鐧藉悕鍗? $ExpectedStrategyIp"         } else {             Warn "鏈湪 config.py 涓娴嬪埌绛栫暐鏈?IP: $ExpectedStrategyIp"         }     } } else {     Fail "鎵句笉鍒伴厤缃枃浠? src\config.py" }  Section "4) MySQL 鍙傛暟妫€鏌ワ紙鍙€夛級" if ($MySqlIniPath -and (Test-Path -LiteralPath $MySqlIniPath)) {     $myini = Get-Content -LiteralPath $MySqlIniPath -Raw     if ($myini -match "innodb_buffer_pool_size\s*=\s*512M") {         Pass "my.ini 宸查厤缃?innodb_buffer_pool_size=512M"     } else {         Warn "my.ini 鏈娴嬪埌 innodb_buffer_pool_size=512M"     }      if ($myini -match "max_connections\s*=\s*50") {         Pass "my.ini 宸查厤缃?max_connections=50"     } else {         Warn "my.ini 鏈娴嬪埌 max_connections=50"     } } else {     Warn "鏈彁渚?MySqlIniPath锛岃烦杩?my.ini 鍙傛暟妫€鏌? }  Section "5) 鏃ュ織涓庤繍琛岀棔杩? $logFiles = @(     "logs\ems_api.out.log",     "logs\ems_api.err.log",     "logs\ems_mail.out.log",     "logs\ems_mail.err.log" ) foreach ($lf in $logFiles) {     $p = Join-Path $ProjectRoot $lf     if (Test-Path -LiteralPath $p) {         Pass "鏃ュ織鏂囦欢瀛樺湪: $lf"     } else {         Warn "鏃ュ織鏂囦欢涓嶅瓨鍦? $lf"     } }  Section "6) Ptrade 妗ユ帴妫€鏌? $bridgePath = Join-Path $ProjectRoot "scripts\ptrade_bridge_template.py" if (Test-Path -LiteralPath $bridgePath) {     $bridge = Get-Content -LiteralPath $bridgePath -Raw     if ($bridge -match "from src.main import main" -and $bridge -match "def initialize\(context\)") {         Pass "妗ユ帴妯℃澘鍐呭瀹屾暣"     } else {         Warn "妗ユ帴妯℃澘鍐呭鍙兘涓嶅畬鏁?     }     Warn "鏃犳硶鑷姩鍒ゆ柇 Ptrade 鍐呯瓥鐣ユ槸鍚﹀凡鐐瑰嚮杩愯锛堥渶浜哄伐纭锛? } else {     Fail "缂哄皯妗ユ帴妯℃澘鏂囦欢" }  if ($CheckSystemTuning) {     Section "7) 绯荤粺璋冧紭妫€鏌ワ紙鍙€夛級"     try {         $visual = Get-ItemProperty -Path "HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\VisualEffects" -ErrorAction SilentlyContinue         if ($null -ne $visual -and $visual.VisualFXSetting -eq 2) {             Pass "瑙嗚鏁堟灉宸茶缃负鏈€浣虫€ц兘锛堝綋鍓嶇敤鎴凤級"         } else {             Warn "鏈‘璁よ瑙夋晥鏋?鏈€浣虫€ц兘锛堣鎵嬪伐纭锛?         }     }     catch {         Warn "鏃犳硶璇诲彇瑙嗚鏁堟灉閰嶇疆"     }      try {         $page = Get-CimInstance Win32_PageFileSetting -ErrorAction SilentlyContinue         if ($null -eq $page) {             Warn "鏈鍙栧埌鍒嗛〉鏂囦欢璁剧疆锛堝彲鑳界郴缁熻嚜鍔ㄧ鐞嗭級"         } else {             $matched = $false             foreach ($it in $page) {                 if (($it.InitialSize -ge 8192 -and $it.InitialSize -le 16384) -or ($it.MaximumSize -ge 8192 -and $it.MaximumSize -le 16384)) {                     $matched = $true                 }             }             if ($matched) {                 Pass "妫€娴嬪埌铏氭嫙鍐呭瓨閰嶇疆鍦ㄥ缓璁寖鍥达紙8~16GB锛?             } else {                 Warn "鏈娴嬪埌寤鸿鐨勮櫄鎷熷唴瀛橀厤缃紙8~16GB锛?             }         }     }     catch {         Warn "鏃犳硶璇诲彇铏氭嫙鍐呭瓨閰嶇疆"     } }  Section "姹囨€? Write-Host "閫氳繃: $($Script:PassCount)" -ForegroundColor Green Write-Host "璀﹀憡: $($Script:WarnCount)" -ForegroundColor Yellow Write-Host "澶辫触: $($Script:FailCount)" -ForegroundColor Red  if ($Script:FailCount -eq 0) {     Write-Host "妫€鏌ュ畬鎴愶細鏃犵‖澶辫触椤广€? -ForegroundColor Green } else {     Write-Host "妫€鏌ュ畬鎴愶細瀛樺湪澶辫触椤癸紝寤鸿鍏堜慨澶?FAIL銆? -ForegroundColor Red }  Write-Host "鎻愰啋锛氭渶鍏抽敭浜哄伐椤规槸鈥淧trade 瀹㈡埛绔唴妗ユ帴绛栫暐宸茶繍琛屸€濄€? -ForegroundColor Yellow